// src/tools/system/sleep/index.ts
async function createSleepTool() {
  const description = "Pause execution for a specified duration.\n\nUsage:\n- duration_ms: milliseconds to sleep (max 60000 = 1 minute)\n- Use sparingly \u2014 prefer event-driven patterns over polling with sleep";
  return {
    name: "sleep",
    description,
    inputSchema: {
      type: "object",
      properties: {
        duration_ms: { type: "number", description: "Milliseconds to sleep (max: 60000)" }
      },
      required: ["duration_ms"]
    },
    async call(input, ctx) {
      const ms = Math.min(typeof input["duration_ms"] === "number" ? input["duration_ms"] : 1e3, 6e4);
      if (ms <= 0) return { content: "Error: duration_ms must be positive", isError: true };
      await new Promise((resolve8, reject) => {
        let settled = false;
        let timer;
        const onAbort = () => {
          if (settled) return;
          settled = true;
          clearTimeout(timer);
          reject(new Error("Sleep aborted"));
        };
        timer = setTimeout(() => {
          if (settled) return;
          settled = true;
          ctx.abortSignal.removeEventListener("abort", onAbort);
          resolve8();
        }, ms);
        if (ctx.abortSignal.aborted) {
          onAbort();
          return;
        }
        ctx.abortSignal.addEventListener("abort", onAbort, { once: true });
      });
      return { content: `Slept for ${ms}ms`, isError: false };
    }
  };
}

// src/tools/system/cron_create/index.ts
async function createCronCreateTool() {
  const description = "Schedule a recurring task using a cron expression.\n\nThe task will run in-process on the given schedule for the lifetime of this session.\nReturns a unique job ID that can be used with `cron_delete` to cancel the job.\n\nCron expression format: `second minute hour day month weekday`  \nStandard 6-field format (e.g. `0 */5 * * * *` = every 5 minutes).  \nUse `cron_list` to inspect all scheduled jobs.";
  return {
    name: "cron_create",
    description,
    inputSchema: {
      type: "object",
      properties: {
        expression: {
          type: "string",
          description: 'Cron expression (6 fields: second minute hour dom month dow). E.g. "0 */5 * * * *" = every 5 minutes.'
        },
        description: {
          type: "string",
          description: "Human-readable description of what this job does."
        },
        command: {
          type: "string",
          description: "(Optional) Shell command to run on each tick. Executed via bash -c."
        }
      },
      required: ["expression", "description"]
    },
    async call(input, ctx) {
      const expression = String(input["expression"] ?? "").trim();
      const desc = String(input["description"] ?? "").trim();
      const command = input["command"] ? String(input["command"]) : void 0;
      if (!expression) return { content: "Error: expression is required", isError: true };
      if (!desc) return { content: "Error: description is required", isError: true };
      try {
        let callback;
        if (command) {
          const { execFile: execFile6 } = await import("child_process");
          const { promisify: promisify6 } = await import("util");
          const execFileAsync6 = promisify6(execFile6);
          callback = async () => {
            await execFileAsync6("bash", ["-c", command], { timeout: 3e4 });
          };
        } else {
          callback = () => {
          };
        }
        const job = createCronJob(expression, desc, ctx.sessionId, callback);
        return {
          content: JSON.stringify({
            job_id: job.id,
            expression: job.expression,
            description: job.description,
            created_at: job.createdAt.toISOString(),
            message: `Cron job scheduled. Use cron_delete with id "${job.id}" to cancel.`
          }, null, 2),
          isError: false
        };
      } catch (err) {
        return {
          content: `Error creating cron job: ${err instanceof Error ? err.message : String(err)}`,
          isError: true
        };
      }
    }
  };
}

// src/tools/system/cron_delete/index.ts
async function createCronDeleteTool() {
  const description = "Cancel a scheduled cron job by its job ID.\n\nUse `cron_list` to find the ID of a running job.\nReturns a confirmation message or an error if the job does not exist.";
  return {
    name: "cron_delete",
    description,
    inputSchema: {
      type: "object",
      properties: {
        job_id: { type: "string", description: "The job ID returned by cron_create." }
      },
      required: ["job_id"]
    },
    async call(input, _ctx) {
      const jobId = String(input["job_id"] ?? "").trim();
      if (!jobId) return { content: "Error: job_id is required", isError: true };
      const deleted = deleteCronJob(jobId);
      if (!deleted) {
        return {
          content: `Error: no cron job found with id "${jobId}". Use cron_list to see active jobs.`,
          isError: true
        };
      }
      return { content: `Cron job "${jobId}" cancelled successfully.`, isError: false };
    }
  };
}

// src/tools/system/cron_list/index.ts
async function createCronListTool() {
  const description = "List all scheduled cron jobs for the current session.\n\nReturns a table of job IDs, cron expressions, task descriptions, and whether each job is currently active.";
  return {
    name: "cron_list",
    description,
    isConcurrencySafe: true,
    inputSchema: {
      type: "object",
      properties: {
        all_sessions: {
          type: "boolean",
          description: "If true, list jobs from all sessions. Default: only current session."
        }
      },
      required: []
    },
    async call(input, ctx) {
      const allSessions = input["all_sessions"] === true;
      const jobs = listCronJobs(allSessions ? void 0 : ctx.sessionId);
      if (jobs.length === 0) {
        return {
          content: allSessions ? "No scheduled cron jobs found." : "No scheduled cron jobs for this session. Use cron_create to schedule one.",
          isError: false
        };
      }
      const rows = jobs.map(
        (j) => [
          `ID:         ${j.id}`,
          `Expression: ${j.expression}`,
          `Desc:       ${j.description}`,
          `Status:     ${j.active ? "active" : "inactive"}`,
          `Runs:       ${j.runCount}`,
          `Last run:   ${j.lastRunAt ? j.lastRunAt.toISOString() : "never"}`,
          `Created:    ${j.createdAt.toISOString()}`
        ].join("\n")
      );
      return { content: rows.join("\n\n"), isError: false };
    }
  };
}

// src/tools/system/enter_plan_mode/index.ts
async function createEnterPlanModeTool(planModeRef) {
  const description = "Switch the session into **plan mode**.\n\nIn plan mode every tool call that has side-effects (writes, shell commands, MCP mutations) requires explicit user approval before it executes. Read-only tools (read_file, glob, grep, web_fetch, etc.) are unaffected and continue to run freely.\n\nUse plan mode when you want to show the user what you intend to do before committing any changes.  \nCall `exit_plan_mode` to return to normal execution.";
  return {
    name: "enter_plan_mode",
    description,
    isConcurrencySafe: true,
    // toggling a flag has no filesystem side-effects
    inputSchema: {
      type: "object",
      properties: {},
      required: []
    },
    async call(_input, _ctx) {
      if (planModeRef.active) {
        return { content: "Already in plan mode. Use exit_plan_mode to leave.", isError: false };
      }
      planModeRef.active = true;
      return {
        content: [
          "\u2705 Plan mode activated.",
          "",
          "All side-effecting tool calls (write_file, edit_file, bash, powershell, mcp_call\u2026)",
          "will now pause and ask for your approval before executing.",
          "Read-only tools (read_file, glob, grep, web_fetch\u2026) continue to run freely.",
          "",
          "Call exit_plan_mode to return to normal execution."
        ].join("\n"),
        isError: false
      };
    }
  };
}

// src/tools/system/exit_plan_mode/index.ts
async function createExitPlanModeTool(planModeRef) {
  const description = "Exit plan mode and return to normal execution.\n\nAfter calling this tool all subsequent tool calls will execute immediately without requiring user approval, just as before plan mode was entered.\n\nOnly valid if plan mode is currently active; returns an error otherwise.";
  return {
    name: "exit_plan_mode",
    description,
    isConcurrencySafe: true,
    inputSchema: {
      type: "object",
      properties: {},
      required: []
    },
    async call(_input, _ctx) {
      if (!planModeRef.active) {
        return { content: "Not in plan mode. Call enter_plan_mode first.", isError: true };
      }
      planModeRef.active = false;
      return {
        content: "\u2705 Plan mode deactivated. Tools will now execute without approval.",
        isError: false
      };
    }
  };
}

