import { mkdir as mkdir16, readFile as readFile22, writeFile as writeFile15 } from "fs/promises";
import { dirname as dirname11, join as join31, resolve as resolve6 } from "path";
var SETTINGS_FILE = join31(".claude", "settings.json");
function settingsPath(cwd) {
  return join31(resolve6(cwd ?? process.cwd()), SETTINGS_FILE);
}
async function readSettings(path4) {
  try {
    return JSON.parse(await readFile22(path4, "utf-8"));
  } catch {
    return {};
  }
}
async function writeSettings(path4, data) {
  await mkdir16(dirname11(path4), { recursive: true });
  await writeFile15(path4, JSON.stringify(data, null, 2) + "\n", "utf-8");
}
function getNestedValue(obj, key) {
  const parts = key.split(".");
  let cur = obj;
  for (const p of parts) {
    if (cur === null || typeof cur !== "object") return void 0;
    cur = cur[p];
  }
  return cur;
}
function setNestedValue(obj, key, value) {
  const parts = key.split(".");
  let cur = obj;
  for (let i = 0; i < parts.length - 1; i++) {
    const p = parts[i];
    if (typeof cur[p] !== "object" || cur[p] === null) cur[p] = {};
    cur = cur[p];
  }
  cur[parts[parts.length - 1]] = value;
}
function deleteNestedValue(obj, key) {
  const parts = key.split(".");
  let cur = obj;
  for (let i = 0; i < parts.length - 1; i++) {
    const p = parts[i];
    if (typeof cur[p] !== "object" || cur[p] === null) return false;
    cur = cur[p];
  }
  const last = parts[parts.length - 1];
  if (!(last in cur)) return false;
  delete cur[last];
  return true;
}
async function createConfigTool(cwd) {
  const description = "Read and write session configuration stored in `.claude/settings.json`.\n\nActions:\n- `get`   \u2014 read the value of a specific key (dot-notation supported, e.g. `model.default`)\n- `set`   \u2014 write a value to a key (value may be any JSON-serialisable type)\n- `list`  \u2014 return the entire settings object as pretty-printed JSON\n- `delete` \u2014 remove a key from the settings\n\nSettings are persisted to `<cwd>/.claude/settings.json`.\nIf the file does not exist it is created on the first `set`.\n\nUse this tool to store per-project preferences, model overrides, tool defaults, or any\nkey-value data that should survive across turns.";
  return {
    name: "config",
    description,
    permission: { category: "config", pathFields: [], requiresWorkspace: false, sensitive: true, planMode: "ask" },
    inputSchema: {
      type: "object",
      properties: {
        action: {
          type: "string",
          enum: ["get", "set", "list", "delete"],
          description: "Operation to perform."
        },
        key: {
          type: "string",
          description: "Settings key (dot-notation). Required for get / set / delete."
        },
        value: {
          description: 'Value to set (any JSON-serialisable type). Required for action="set".'
        }
      },
      required: ["action"]
    },
    async call(input, _ctx) {
      const action = String(input["action"] ?? "").trim();
      const key = input["key"] ? String(input["key"]).trim() : void 0;
      const value = input["value"];
      const path4 = settingsPath(cwd);
      try {
        if (action === "list") {
          const settings = await readSettings(path4);
          return {
            content: Object.keys(settings).length === 0 ? `Settings file is empty or does not exist (${path4})` : JSON.stringify(settings, null, 2),
            isError: false
          };
        }
        if (action === "get") {
          if (!key) return { content: 'Error: key is required for action="get"', isError: true };
          const settings = await readSettings(path4);
          const val = getNestedValue(settings, key);
          if (val === void 0) {
            return { content: `Key "${key}" not found in settings.`, isError: false };
          }
          return { content: JSON.stringify(val, null, 2), isError: false };
        }
        if (action === "set") {
          if (!key) return { content: 'Error: key is required for action="set"', isError: true };
          if (value === void 0) return { content: 'Error: value is required for action="set"', isError: true };
          const settings = await readSettings(path4);
          setNestedValue(settings, key, value);
          await writeSettings(path4, settings);
          return {
            content: `Set "${key}" = ${JSON.stringify(value)} in ${path4}`,
            isError: false
          };
        }
        if (action === "delete") {
          if (!key) return { content: 'Error: key is required for action="delete"', isError: true };
          const settings = await readSettings(path4);
          const found = deleteNestedValue(settings, key);
          if (!found) return { content: `Key "${key}" not found; nothing deleted.`, isError: false };
          await writeSettings(path4, settings);
          return { content: `Deleted "${key}" from ${path4}`, isError: false };
        }
        return { content: `Error: unknown action "${action}". Use get / set / list / delete.`, isError: true };
      } catch (err) {
        return {
          content: `Config error: ${err instanceof Error ? err.message : String(err)}`,
          isError: true
        };
      }
    }
  };
}

