// src/tools/agent/run_agent/index.ts
async function createRunAgentTool(bridge) {
  const description = "Run a sub-agent synchronously and wait for its result before continuing.\n\nUnlike spawn_sub_agent (async, returns taskId immediately), run_agent blocks\nuntil the sub-task completes and returns the final result.\n\nWhen to use:\n- When you need the sub-task result before taking the next step\n- Short-running tasks (< 10 turns expected)\n- Sequential workflows with data dependencies\n\nWhen NOT to use:\n- Long-running tasks (> 5 minutes) \u2014 use spawn_sub_agent instead\n- Tasks you can run in parallel \u2014 use multiple spawn_sub_agent calls\n- Tasks where failure should not block the main flow";
  return {
    name: "run_agent",
    description,
    inputSchema: {
      type: "object",
      properties: {
        task_description: { type: "string", description: "Full description of the sub-task. Include all context needed \u2014 the sub-agent starts with an empty conversation." },
        system_prompt: { type: "string", description: "(Optional) System prompt for the sub-agent." },
        allowed_tools: { type: "array", items: { type: "string" }, description: "(Optional) Tools the sub-agent may use." },
        max_turns: { type: "number", description: "Max turns before force-stop. Default: 10." },
        max_budget_usd: { type: "number", description: "Max cost in USD. Default: 0.5." }
      },
      required: ["task_description"]
    },
    async call(input, ctx) {
      const taskDescription = String(input["task_description"] ?? "").trim();
      if (!taskDescription) return { content: "Error: task_description is required", isError: true };
      const maxTurns = typeof input["max_turns"] === "number" ? input["max_turns"] : 10;
      const maxBudgetUsd = typeof input["max_budget_usd"] === "number" ? input["max_budget_usd"] : 0.5;
      const MAX_WAIT_MS = maxTurns * 2 * 60 * 1e3;
      try {
        const record2 = await bridge.spawnSubAgent({
          config: {
            taskDescription,
            systemPrompt: input["system_prompt"],
            allowedTools: input["allowed_tools"],
            maxTurns,
            maxBudgetUsd,
            requireHumanApproval: false,
            useEventDriven: false,
            pollIntervalMs: 500,
            checkpointEveryNTurns: 0
          },
          abortSignal: ctx.abortSignal
        });
        const abortableSleep3 = (ms) => new Promise((resolve8) => {
          let settled = false;
          let timer;
          const onAbort = () => {
            if (settled) return;
            settled = true;
            clearTimeout(timer);
            resolve8();
          };
          timer = setTimeout(() => {
            if (settled) return;
            settled = true;
            ctx.abortSignal.removeEventListener("abort", onAbort);
            resolve8();
          }, ms);
          if (ctx.abortSignal.aborted) {
            onAbort();
            return;
          }
          ctx.abortSignal.addEventListener("abort", onAbort, { once: true });
        });
        const startMs = Date.now();
        while (Date.now() - startMs < MAX_WAIT_MS) {
          if (ctx.abortSignal.aborted) {
            await bridge.cancelTask(record2.taskId, "run_agent aborted").catch(() => {
            });
            return { content: "Sub-agent cancelled (aborted by caller)", isError: true };
          }
          await abortableSleep3(500);
          if (ctx.abortSignal.aborted) {
            await bridge.cancelTask(record2.taskId, "run_agent aborted").catch(() => {
            });
            return { content: "Sub-agent cancelled (aborted by caller)", isError: true };
          }
          const status = await bridge.getStatus(record2.taskId);
          if (!status) return { content: `Internal error: task ${record2.taskId} not found`, isError: true };
          if (status.status === "completed") {
            return {
              content: JSON.stringify({
                success: status.result?.success ?? true,
                summary: status.result?.summary ?? "",
                turns_used: status.result?.turnsUsed,
                cost_usd: status.result?.costUsd,
                duration_ms: status.result?.durationMs
              }, null, 2),
              isError: false
            };
          }
          if (status.status === "failed") return { content: `Sub-agent failed: ${status.result?.error ?? "unknown error"}`, isError: true };
          if (status.status === "cancelled") return { content: "Sub-agent was cancelled", isError: true };
        }
        await bridge.cancelTask(record2.taskId, "run_agent timeout").catch(() => {
        });
        return { content: `Sub-agent timed out after ${Math.round(MAX_WAIT_MS / 1e3)}s`, isError: true };
      } catch (err) {
        return { content: `Error: ${err instanceof Error ? err.message : String(err)}`, isError: true };
      }
    }
  };
}

